SELECT "repo":"name"::string AS repo_name, COUNT(DISTINCT "actor":"id"::string) AS watcher_count FROM "GITHUB_REPOS_DATE"."YEAR"."_2017" INNER JOIN "GITHUB_REPOS_DATE"."GITHUB_REPOS"."SAMPLE_FILES" ON "repo":"name"::string = "GITHUB_REPOS_DATE"."GITHUB_REPOS"."SAMPLE_FILES"."repo_name" WHERE "type" = 'WatchEvent' GROUP BY "repo":"name"::string HAVING watcher_count > 300 ORDER BY watcher_count DESC LIMIT 2